import React, { useState } from 'react';
import './ImportDataSidebar.css';

function ImportDataSidebar({ onSelectUserStory, onClose, isSidebarVisible }) {
  const [domain, setDomain] = useState('');
  const [project, setProject] = useState('');
  const [issueType, setIssueType] = useState('');
  const [username, setUsername] = useState('');  // New state for username
  const [jiraData, setJiraData] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const fetchJiraData = async () => {
    setLoading(true);
    setError(null);

    try {
      const response = await fetch(
        `https://localhost:7216/api/UserStoryDescription/ExportAllUserStories?domain=${domain}&project=${project}&issueType=${issueType}&username=${username}`  // Pass username in the query
      );

      if (!response.ok) {
        throw new Error('Failed to fetch Jira data.');
      }

      const data = await response.json();
      setJiraData(data);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleUserStoryClick = (story) => {
    onSelectUserStory(story);
  };

  const handleClearJiraData = () => {
    setJiraData([]); // Clear the fetched user stories
  };

  return (
    <div className={`import-sidebar ${isSidebarVisible ? 'visible' : ''}`}>
      <button className="close-btn" onClick={onClose}>X</button>
      <div className="sidebar-title"><strong>Fetch Jira User Stories</strong></div>

      <div className="input-fields">
        <input
          type="text"
          placeholder="Domain"
          value={domain}
          onChange={(e) => setDomain(e.target.value)}
        />
        <input
          type="text"
          placeholder="Project"
          value={project}
          onChange={(e) => setProject(e.target.value)}
        />
        <input
          type="text"
          placeholder="Issue Type"
          value={issueType}
          onChange={(e) => setIssueType(e.target.value)}
        />
        <input
          type="text"
          placeholder="Jira Username"
          value={username}
          onChange={(e) => setUsername(e.target.value)}  // Bind username input
        />

        <div className="button-container">
          <button onClick={fetchJiraData} disabled={loading}>
            {loading ? 'Fetching...' : 'Fetch Data'}
          </button>
          <button className="clear-button" onClick={handleClearJiraData}>
            Clear Data
          </button>
        </div>
      </div>

      {loading && <div>Loading...</div>}
      {error && <div className="error">{error}</div>}

      <div className="jira-stories">
        {jiraData && jiraData.length > 0 ? (
          jiraData.map((story, index) => (
            <div
              key={index}
              onClick={() => handleUserStoryClick(story)}
              className="jira-story-box"
            >
              <h4>{story.summary}</h4>
              <p><strong>Assignee:</strong> {story.reporter}</p>
              <p><strong>Description:</strong> {story.description}</p>
            </div>
          ))
        ) : (
          !loading && <div>No stories found.</div>
        )}
      </div>
    </div>
  );
}

export default ImportDataSidebar;
